diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..48c2b546cac6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2226,9 +2226,47 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
   Value *Op1 = I.getOperand(1);
   Type *Ty = I.getType();
   auto *MinMax = dyn_cast<MinMaxIntrinsic>(Op1);
+
+
   if (!MinMax)
     return nullptr;

+  // If both operands are min/max of the same kind:
+  // sub(smin(add nsw X, 1), Y), smin(X, Y)) -> zext(icmp slt X, Y)
+  // sub(umin(add nuw X, 1), Y), umin(X, Y)) -> zext(icmp ult X, Y)
+  // Also matches or disjoint X, 1 as equivalent to add nuw nsw X, 1.
+  if (Ty->getScalarSizeInBits() > 1 && MinMax->hasOneUse()) {
+    if (auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0)) {
+      if (MinMax0->getIntrinsicID() == MinMax->getIntrinsicID() &&
+          MinMax0->getRHS() == MinMax->getRHS()) {
+        Value *X0 = MinMax0->getLHS();
+        Value *X1 = MinMax->getLHS();
+        const APInt *C;
+        // Match add nsw/nuw X, C or or disjoint X, C with C=1.
+        bool Valid = false;
+        if (match(X0, m_Add(m_Specific(X1), m_APInt(C)))) {
+          if (C->isOne()) {
+            bool IsSigned = MinMax->isSigned();
+            if ((IsSigned && cast<OverflowingBinaryOperator>(X0)->hasNoSignedWrap()) ||
+                (!IsSigned && cast<OverflowingBinaryOperator>(X0)->hasNoUnsignedWrap()))
+              Valid = true;
+          }
+        } else if (match(X0, m_DisjointOr(m_Specific(X1), m_APInt(C)))) {
+          if (C->isOne())
+            Valid = true;
+        }
+        if (Valid) {
+          bool IsSigned = MinMax->isSigned();
+          Value *Cmp = Builder.CreateICmp(IsSigned ? ICmpInst::ICMP_SLT
+                                                   : ICmpInst::ICMP_ULT,
+                                          X1, MinMax->getRHS());
+          return CastInst::CreateZExtOrBitCast(Cmp, Ty);
+        }
+      }
+    }
+  }
+
+
   // sub(add(X,Y), s/umin(X,Y)) --> s/umax(X,Y)
   // sub(add(X,Y), s/umax(X,Y)) --> s/umin(X,Y)
   Value *X = MinMax->getLHS();

